-- SQL Script for Web Giày Bóng Đá database
CREATE DATABASE IF NOT EXISTS `web_giay_bong_da` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `web_giay_bong_da`;

SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `danhmuc`;
DROP TABLE IF EXISTS `taikhoan`;
DROP TABLE IF EXISTS `banner`;
DROP TABLE IF EXISTS `baiviet`;
DROP TABLE IF EXISTS `sanpham`;
DROP TABLE IF EXISTS `binhluan`;
DROP TABLE IF EXISTS `donhang`;
DROP TABLE IF EXISTS `chitiet_donhang`;
SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE `danhmuc` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `ten_danhmuc` varchar(255) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ten_danhmuc` (`ten_danhmuc`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `taikhoan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user` varchar(50) NOT NULL,
  `pass` varchar(255) NOT NULL,
  `email` varchar(100) NOT NULL,
  `dien_thoai` varchar(20) DEFAULT NULL,
  `vai_tro` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user` (`user`),
  UNIQUE KEY `email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `banner` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `ten_banner` varchar(255) NOT NULL,
  `hinh_anh` varchar(255) NOT NULL,
  `lien_ket` varchar(255) DEFAULT NULL,
  `vi_tri` varchar(50) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `baiviet` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `tieu_de` varchar(255) NOT NULL,
  `hinh_anh` varchar(255) NOT NULL,
  `ngay_dang` varchar(20) NOT NULL,
  `mo_ta_ngan` text NOT NULL,
  `noi_dung` text NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `sanpham` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `ten_sanpham` varchar(255) NOT NULL,
  `gia` double NOT NULL,
  `gia_giam` double DEFAULT NULL,
  `hinh_anh` varchar(255) NOT NULL,
  `mo_ta` text DEFAULT NULL,
  `id_danhmuc` int(11) NOT NULL,
  `dac_biet` int(11) DEFAULT 0,
  `luot_xem` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `id_danhmuc` (`id_danhmuc`),
  CONSTRAINT `sanpham_ibfk_1` FOREIGN KEY (`id_danhmuc`) REFERENCES `danhmuc` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=260 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `binhluan` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `noi_dung` text NOT NULL,
  `id_user` int(11) NOT NULL,
  `id_pro` int(11) NOT NULL,
  `ngay_binh_luan` varchar(20) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `id_user` (`id_user`),
  KEY `id_pro` (`id_pro`),
  CONSTRAINT `binhluan_ibfk_1` FOREIGN KEY (`id_user`) REFERENCES `taikhoan` (`id`) ON DELETE CASCADE,
  CONSTRAINT `binhluan_ibfk_2` FOREIGN KEY (`id_pro`) REFERENCES `sanpham` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

CREATE TABLE `donhang` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_user` int(11) DEFAULT NULL,
  `nguoi_nhan` varchar(255) NOT NULL,
  `email` varchar(100) NOT NULL,
  `dien_thoai` varchar(20) NOT NULL,
  `dia_chi` text NOT NULL,
  `ngay_dat` varchar(20) NOT NULL,
  `tong_tien` double NOT NULL,
  `pttt` int(11) DEFAULT 0,
  `trang_thai` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `id_user` (`id_user`),
  CONSTRAINT `donhang_ibfk_1` FOREIGN KEY (`id_user`) REFERENCES `taikhoan` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=291 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


CREATE TABLE `chitiet_donhang` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_donhang` int(11) NOT NULL,
  `id_sanpham` int(11) NOT NULL,
  `ten_sanpham` varchar(255) NOT NULL,
  `hinh_anh` varchar(255) NOT NULL,
  `gia` double NOT NULL,
  `so_luong` int(11) NOT NULL,
  `size` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `id_donhang` (`id_donhang`),
  KEY `id_sanpham` (`id_sanpham`),
  CONSTRAINT `chitiet_donhang_ibfk_1` FOREIGN KEY (`id_donhang`) REFERENCES `donhang` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chitiet_donhang_ibfk_2` FOREIGN KEY (`id_sanpham`) REFERENCES `sanpham` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=423 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


