('10', 'Adidas F50 League TF IF1336 - Xanh/Hồng', '2400000', '1490000', 'assets/images/adidas_f50_league.png', 'Dòng sản phẩm F50 tốc độ huyền thoại của Adidas, sắc xanh phối hồng cá tính và đệm đế giảm áp suất gót chân.', '1', '1', '120'),
('11', 'Puma Future 8 Pro Cage TT Audacity - 108366-03', '2999000', '1750000', 'assets/images/puma_future8.png', 'Thiết kế giày đinh dăm chuyên dụng cho sân cỏ nhân tạo với chất liệu thun co giãn ôm khít cổ chân cực tốt.', '1', '1', '132'),
('12', 'Giày Bóng Đá Kelme TF Mã 8531ZX1036', '1040000', '936000', 'assets/images/kelme_tf.png', 'Giày bóng đá Kelme chính hãng bền bỉ, thích hợp cho người chân bè, thiết kế màu bạc thời thượng và ôm chân thoải mái.', '1', '1', '144'),
